<section class="admin-page-head"><div><p class="eyebrow">FULFILLMENT / AWB</p><h1><?= e($order['order_number']) ?></h1><p>Generarea este idempotentă: apăsarea repetată nu dublează expediția.</p></div><a class="admin-button secondary" href="<?= e(url('/admin/comenzi/'.$order['id'])) ?>">Înapoi la comandă</a></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><?php if($error): ?><div class="admin-alert error"><?= e($error) ?></div><?php endif; ?><div class="admin-two-columns"><section class="admin-panel"><h2>Destinație</h2><dl class="admin-details"><dt>Client</dt><dd><?= e(($order['shipping_address']['first_name']??'').' '.($order['shipping_address']['last_name']??'')) ?></dd><dt>Adresă</dt><dd><?= e($order['shipping_address']['line1']??'') ?></dd><dt>Localitate</dt><dd><?= e(($order['shipping_address']['city']??'').' '.($order['shipping_address']['county']??'')) ?></dd><dt>Telefon</dt><dd><?= e($order['phone']) ?></dd><dt>Ramburs</dt><dd><?= $order['payment_method']==='cod'?money($order['grand_total_minor']):'Nu' ?></dd></dl><?php if($shipment): ?><div class="shipment-result"><p class="eyebrow">EXPEDIȚIE EXISTENTĂ</p><h2><?= e($shipment['awb']?:'În coada API') ?></h2><p><?= e($shipment['provider_name']?:'Curier') ?> · <?= e($shipment['status']) ?></p></div><?php endif; ?></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/comenzi/'.$order['id'].'/awb')) ?>"><?= csrf_field() ?><h2>Configurare colet</h2><label>Curier<select name="provider_id" required><?php foreach($providers as $provider): ?><option value="<?= (int)$provider['id'] ?>"><?= e($provider['name']) ?><?= $provider['is_default']?' · implicit':'' ?></option><?php endforeach; ?></select></label><label>Greutate (grame)<input type="number" min="1" name="weight_grams" value="1000"></label><label>Număr colete<input type="number" min="1" name="parcels" value="1"></label><button class="admin-button" type="submit"><?= $shipment?'Vezi/confirmă expediția':'Generează AWB' ?></button><p class="help">Curierul manual emite imediat un număr intern. Conectorii API creează un job și nu marchează expedierea reușită înainte de răspunsul furnizorului.</p></form></aside></div>
